mapper.select:
select *
from jsh_customer_follow_up
where 1=1
and ifnull(delete_flag, '0') != '1'

    and customer_id = #{customerId}


    and follow_up_type = #{followUpType}


    and follow_up_status = #{followUpStatus}


    and operator like concat('%', #{operator}, '%')


    and follow_up_time >= #{beginTime}


    and follow_up_time <= #{endTime}

order by follow_up_time desc

    limit #{offset}, #{rows}

select count(1)
from jsh_customer_follow_up
where 1=1
and ifnull(delete_flag, '0') != '1'

    and customer_id = #{customerId}


    and follow_up_type = #{followUpType}


    and follow_up_status = #{followUpStatus}


    and operator like concat('%', #{operator}, '%')


    and follow_up_time >= #{beginTime}


    and follow_up_time <= #{endTime}

select cfu.*, s.supplier as customer_name, u.username as user_name
from jsh_customer_follow_up cfu
left join jsh_supplier s on cfu.customer_id = s.id and s.delete_flag = '0'
left join jsh_user u on cfu.handler_id = u.id and u.Status = '0'
where 1=1
and ifnull(cfu.delete_flag, '0') != '1'
and cfu.is_handler_record = '1'

    and cfu.customer_id = #{customerId}


    and cfu.handler_id = #{handlerId}


    and cfu.follow_up_time >= #{beginTime}


    and cfu.follow_up_time <= #{endTime}

order by cfu.follow_up_time desc

    limit #{offset}, #{rows}

select count(1)
from jsh_customer_follow_up
where 1=1
and ifnull(delete_flag, '0') != '1'
and is_handler_record = '1'

    and customer_id = #{customerId}


    and handler_id = #{handlerId}


    and follow_up_time >= #{beginTime}


    and follow_up_time <= #{endTime}
